DATABASE_URI = 'sqlite:///mydatabase.db'
engine = sqlalchemy.create_engine(DATABASE_URI)

@app.route('/data', methods=['POST'])
def create_data():
    data = request.json
    with engine.connect() as connection:
        result = connection.execute("INSERT INTO my_table (name) VALUES (:name)", {'name': data['name']})
    return jsonify({'status': 'success', 'id': result.lastrowid}), 201

@app.route('/data/<int:data_id>', methods=['GET'])
def get_data(data_id):
    with engine.connect() as connection:
        result = connection.execute("SELECT * FROM my_table WHERE id = :id", {'id': data_id})
        row = result.fetchone()
    if row:
        return jsonify({'id': row['id'], 'name': row['name']}), 200
    return jsonify({'error': 'Not found'}), 404

